<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>

    <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">

                <!-- Header -->
                <div class="modal-header theme-primary partition-full d-flex">
                    <h4 class="modal-title">{{ $t('CopyRate') }}</h4>

                    <button type="button" class="close" @click="Close">
                        <em class="fa fa-times"></em>
                    </button>
                </div>

                <!-- Body -->
                <div class="modal-body">
                    <dynamic-form
                        ref="ResourceRate"
                        :schema="FormSchema"
                        :buttons="buttons"
                        :mandatorytext="MandatoryString"
                        @OnSubmit="onSubmit"
                    />
                </div>

            </div>
        </div>
    </div>
</div>
</template>

<script>
export default {
    props: {
        EditData: Array
    },

    data() {
        return {
            isLoading: false,
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            companyId: null,
            userId: null,

            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "DateField",
                            label: this.$t('Start Date (M/D/YYYY)'),
                            name: "StartDate",
                            value: new Date(),
                            config: {
                                format: "MM/DD/YYYY",
                                onChange: this.onStartDateChange
                            },
                            validationRules: { required: true }
                        },

                        {
                            astype: "DateField",
                            label: this.$t('End Date (M/D/YYYY)'),
                            name: "EndDate",
                            value: '',
                            config: { format: "MM/DD/YYYY" },
                            validationRules: { required: true }
                        },

                        {
                            astype: "RadioField",
                            label: '',
                            name: "PreviousRecordAction",
                            value: 1, 
                            config: {
                                options: [
                                    {
                                        value: 1,
                                        name: ''
                                    },
                                    {
                                        value: 2,
                                        name: this.$t('Do you want to mark previous Records as Inactive?')
                                    }
                                ]
                            }
                        }
                    ]
                },

                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextAreaField",
                            label: this.$t('Comment'),
                            name: "Comment",
                            value: "",
                            placeholder: this.$t('Enter Comment')
                        }
                    ]
                }
            ],

            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Set New Dates",
                    isVisible: true
                }
            ]
        };
    },

    created() {
        this.userId = this.GetUserInfo?.ID;
        this.companyId = this.GetUserInfo?.CompanyId;

        this.updatePreviousRecordText(this.FormSchema[0].Data[0].value);
    },

    methods: {
        getPreviousDate(date) {
            const d = new Date(date);
            d.setDate(d.getDate() - 1);
            return d.toLocaleDateString();
        },

        updatePreviousRecordText(startDate) {
            const prevDate = this.getPreviousDate(startDate);
            const radio = this.FormSchema[0].Data.find(
                f => f.name === 'PreviousRecordAction'
            );
            radio.config.options[0].name =
                `${this.$t('previous records End Date will be updated as:')} ${prevDate}`;
        },

        onStartDateChange(value) {
            this.updatePreviousRecordText(value);
        },

        getSelectedAction() {
            const value = this.FormSchema[0].Data
                .find(f => f.name === 'PreviousRecordAction').value;

            return value === 1
                ? 'UPDATE_END_DATE'
                : 'MARK_AS_INACTIVE';
        },

        onSubmit(formfields) {
            if (!this.$refs.ResourceRate.validateForm.validate()) return;

            const payload = {
                ids: this.EditData
                    .filter(x => x.isSelected)
                    .map(x => x.RATE_SCHEDULE_ID),

                newStartDate: formfields.StartDate,
                newEndDate: formfields.EndDate,
                action: this.getSelectedAction()
            };

            this.$emit("navigateToSelected", payload);
        },

        Close() {
            this.$parent.isCopyRate = false;
        }
    }
};
</script>
