                            name: "UtilityName",
                            value: "",
                            placeholder: "Select Utility Name",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                            },
                            validationRules: {
                                "required": true
                            },
                            disabled: false
                        },
                    {
                        astype: "SelectField",
                        label: this.$t('State'),
